import React, { useState, useEffect, useRef } from 'react';
import '../assets/styles/Keyboard_mouse.css'; // Importăm fișierul CSS separat

const Keyboard_mouse = () => {
  const [startTouch, setStartTouch] = useState(null);  // Punctul de început al atingerii
  const [isClick, setIsClick] = useState(true);  // Stare pentru a detecta dacă e un click simplu sau mișcare
  const [socket, setSocket] = useState(null);  // WebSocket
  const sensitivity = 2;  // Factorul de sensibilitate pentru mișcarea cursorului
  const socketRef = useRef(null);  // Reținem referința WebSocket pentru reutilizare

  useEffect(() => {
    // Inițializăm WebSocket-ul la montarea componentului
    const ws = new WebSocket('ws://localhost:8000/ws/mouse/');
    ws.onopen = () => {
      console.log('WebSocket connection opened');
    };
    
    ws.onclose = () => {
      console.log('WebSocket connection closed');
    };
    
    ws.onerror = (error) => {
      console.error('WebSocket error:', error);
    };

    setSocket(ws);
    socketRef.current = ws; // Salvăm referința pentru reutilizare

    return () => {
      // Închidem WebSocket-ul la demontarea componentului
      ws.close();
    };
  }, []);

  const sendMouseMove = (deltaX, deltaY) => {
    if (socketRef.current && socketRef.current.readyState === WebSocket.OPEN) {
      socketRef.current.send(JSON.stringify({ action: 'move', x: deltaX, y: deltaY }));
    }
  };

  const sendMouseClick = (button = 'left', double = false) => {
    if (socketRef.current && socketRef.current.readyState === WebSocket.OPEN) {
      socketRef.current.send(JSON.stringify({ action: 'click', button: button, double: double }));
    }
  };

  const handleTouchStart = (event) => {
    const touch = event.touches[0];
    setStartTouch({ x: touch.clientX, y: touch.clientY });
    setIsClick(true);
  };

  const handleTouchMove = (event) => {
    event.preventDefault();
    const touch = event.touches[0];

    if (startTouch) {
      const deltaX = (touch.clientX - startTouch.x) * sensitivity;
      const deltaY = (touch.clientY - startTouch.y) * sensitivity;

      if (Math.abs(deltaX) > 5 || Math.abs(deltaY) > 5) {
        setIsClick(false);
      }

      sendMouseMove(deltaX, deltaY);
      setStartTouch({ x: touch.clientX, y: touch.clientY });
    }
  };

  const handleTouchEnd = () => {
    if (isClick) {
      sendMouseClick('left');
    }
    setStartTouch(null);
  };

  const handleRightClick = (event) => {
    event.preventDefault();
    sendMouseClick('right');
  };

  const handleDoubleClick = () => {
    sendMouseClick('left', true);
  };

  return (
    <div
      className="touchpad-container"
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
      onContextMenu={handleRightClick}  // Captură pentru click dreapta
      onDoubleClick={handleDoubleClick}  // Captură pentru dublu click
    >
      <h2>Touchpad Controller</h2>
      <p>Use the touchpad to move the mouse and tap to clickkkkkkkkkkk.</p>
      <p>Right-click by long-pressing or double-tap for double-click.</p>
    </div>
  );
};

export default Keyboard_mouse;
